"""
MKT Original Commentary — 2 Chronicles chapters 21–24
Run: python3 scripts/zc-original-2chronicles-21-24.py

Key philological decisions:
- Ch21: nîr (lamp) = Davidic dynastic term (v7); ḥemdāh absence = dishonor formula (v20);
  Elijah's miktāb (letter) addressed before his translation (v12)
- Ch22: 42 vs 22 age discrepancy at v2 (MT vs 2 Kgs 8:26); mēʾĕlōhîm (from God) = divine
  sovereignty formula (v7); dārash (seek) as Chronicler's evaluation term (v9)
- Ch23: hāʿēḏût (the testimony) = the covenant document placed on the king at coronation (v11);
  lāḇᵉšāh rûaḥ (Spirit clothed) at 24:20 = vestment-Spirit idiom
- Ch24: midrash (commentary) as the one pre-rabbinic use of the term in OT (v27);
  ḥeseḏ-failure as the hinge of Joash's apostasy narrative (v22)
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ORIGINAL = {
  "21": {
    "1": "<p>The transition formula <em>wayyiškab Yehōšāpāṭ ʿim-ʾăḇōtāyw</em> (&lsquo;Jehoshaphat lay down with his ancestors&rsquo;) is the standard regnal conclusion formula (cf. 1 Kgs 11:43; 14:20; 15:8). Burial in the <em>ʿîr Dāwîd</em> (city of David) was the honorific resting place for Judah&rsquo;s faithful kings; its mention here contrasts with Jehoram&rsquo;s exclusion from the royal tombs in v20. The succession formula <em>wayyimlōḵ ʾaḥăzYāhû bᵉnô taḥtāyw</em> (&lsquo;his son Ahaziah reigned in his place&rsquo;) is formulaic but the Chronicler uses the correct dynastic name here (cf. ch22).</p>",
    "2": "<p>Jehoshaphat&rsquo;s sons are listed with two sons named &lsquo;Azariah&rsquo; — a duplication the Chronicler preserves without harmonization. This is characteristic of Hebrew name-lists where family naming patterns led to identical names in the same generation. The list closes with the explanatory phrase <em>kōl-ʾēlleh bᵉnê Yehōšāpāṭ melek Yiśrāʾēl</em> (&lsquo;all these are sons of Jehoshaphat king of Israel&rsquo;), using <em>Yiśrāʾēl</em> rather than <em>Yᵉhûdāh</em> — the Chronicler&rsquo;s inclusive usage for the whole covenant people under the Davidic king.</p>",
    "3": "<p><em>Mattānôt rabbôt</em> (&lsquo;generous gifts&rsquo;) — the plural of <em>mattānāh</em> (gift, given thing; H4976) reflects the ANE practice of providing for secondary sons to forestall succession conflict. <em>ʿārê mibṣār</em> (&lsquo;fortified cities&rsquo;) given to the brothers created regional power bases outside Jerusalem. The causal <em>kî hûʾ habbᵉḵôr</em> (&lsquo;for he was the firstborn&rsquo;) — <em>bᵉḵôr</em> (H1060) carries ANE legal weight as the heir to both the doubled inheritance and, in Judah&rsquo;s case, the dynastic succession.</p>",
    "4": "<p><em>wayyitḥazzaq Yᵉhôrām</em> (&lsquo;Jehoram established himself&rsquo;) — the Hithpael of <em>ḥāzaq</em> (H2388) carries a reflexive-assertive sense: he strengthened himself into position, seized power. The verb is frequently used for military or political consolidation. <em>wayya-harōg ʾet-kol-ʾeḥāyw beḥāreḇ</em> (&lsquo;he put all his brothers to the sword&rsquo;) — <em>hārag</em> (H2026): to kill, slay. The phrase <em>û-miśśārê Yiśrāʾēl</em> (&lsquo;and some of the Israelite leaders&rsquo;) is unique to Chronicles, indicating purge beyond the family.</p>",
    "5": "<p>The accession formula <em>ben-šelōšîm ûšetayim šānāh Yᵉhôrām bᵉmalᵉkô</em> follows the standard pattern: age at accession + regnal length. Jehoram&rsquo;s eight-year reign (eight being the most frequent number for short, uninspiring reigns in the Chronicler&rsquo;s framework) combines with his age (thirty-two) to mark him as relatively young at accession yet without the energy of genuine reform. The Chronicler notes Jerusalem without the usual <em>ûšᵉmô ʾimmô</em> (&lsquo;and his mother&rsquo;s name was&rsquo;) formula, a notable omission.</p>",
    "6": "<p>The evaluation formula <em>wayyēlek bᵉdereḵ malkê Yiśrāʾēl</em> (&lsquo;he followed the way of the kings of Israel&rsquo;) — <em>dereḵ</em> (H1870): way, road, manner — is the Chronicler&rsquo;s behavioral shorthand for Baal-worship patterns. The reason given: <em>kî bat-ʾAḥʾāḇ hāyᵉtāh lô lᵉʾiššāh</em> (&lsquo;because the daughter of Ahab was his wife&rsquo;). The dynastic marriage to the Omride house is the theological-historical explanation for Baal influence in Jerusalem. The standard condemnation <em>wayyaʿaś hāraʿ bᵉʿênê YHWH</em> follows.</p>",
    "7": "<p><em>nîr</em> (H5216) — the &lsquo;lamp&rsquo; or &lsquo;light&rsquo; idiom for Davidic dynastic continuation: YHWH&rsquo;s promise is to provide <em>nîr lô ûlᵉḇānāyw kol-hayyāmîm</em> (&lsquo;a lamp for him and his sons for all days&rsquo;). The image of a lamp that must not go out reflects the threat of dynastic extinction that runs through chs21–24, culminating in the Joash rescue (22:10-12). The Chronicler specifies that YHWH made a <em>bᵉrît</em> (covenant) with David — the Davidic covenant is the theological brake on Jehoram&rsquo;s destructive reign. Without it, the dynasty would have been destroyed for its wickedness.</p>",
    "8": "<p><em>pāšaʿ ʾĕdôm mittaḥat yad-Yᵉhûdāh</em> (&lsquo;Edom rebelled against Judah&rsquo;s authority&rsquo;) — <em>pāšaʿ</em> (H6586): to rebel, transgress, break away. Edom&rsquo;s subjection to Judah had been established under David (2 Sam 8:14) and Jehoshaphat maintained it. The rebellion is both political and the Chronicler&rsquo;s theological sign of YHWH withdrawing protection from Jehoram&rsquo;s kingdom. <em>wayyamlîḵû ʿălêhem melek</em> (&lsquo;and crowned their own king&rsquo;) — they installed their own king against Judah&rsquo;s suzerainty.</p>",
    "9": "<p><em>wayyaʿăḇōr Yᵉhôrām ʿim-śārāyw</em> (&lsquo;Jehoram crossed over with his commanders&rsquo;) — <em>ʿāḇar</em> (H5674) with military connotations: to cross over, march through. The phrase <em>wayyāqom laylāh wayyak ʾet-ʾĔdôm</em> (&lsquo;he got up at night and broke through&rsquo;) — the night assault; <em>nākāh</em> (H5221): to smite, strike. The parallel in 2 Kgs 8:21 is similar. The Chronicler&rsquo;s &lsquo;when the Edomites surrounded him and his chariot commanders&rsquo; clarifies that Jehoram barely escaped; this is not a victory but an escape from encirclement.</p>",
    "10": "<p><em>wayyipšaʿ ʾĔdôm mittaḥat yad-Yᵉhûdāh ʿad hayyôm hazzeh</em> (&lsquo;Edom has remained independent to this day&rsquo;) — the historian&rsquo;s perspective; <em>ʿad hayyôm hazzeh</em> is a common formulaic anchor to the time of writing, confirming the permanent loss. The coordinate clause <em>ʾāz tipšaʿ Libnāh</em> (&lsquo;at the same time Libnah rebelled&rsquo;) — a southwestern city on the Philistine border. The causal particle <em>kî ʿāzaḇ ʾet-YHWH</em> (&lsquo;because he abandoned the LORD&rsquo;) — <em>ʿāzaḇ</em> (H5800): to abandon, leave; the Chronicler&rsquo;s key apostasy verb.</p>",
    "11": "<p><em>bāmôt</em> (H1116) — the high places: unauthorized worship sites condemned throughout Kings/Chronicles as violations of centralized cult at Jerusalem. <em>wayyizᵉneh ʾet-yōšᵉḇê Yᵉrûšālayim</em> (&lsquo;seduced the people of Jerusalem into spiritual prostitution&rsquo;) — <em>zānāh</em> (H2181, Hiphil): to cause to play the whore; the idiom of spiritual unfaithfulness used for idolatry throughout the Prophets (Hos 1:2; Jer 2:20). MKT renders &lsquo;spiritual prostitution&rsquo; to capture the metaphorical force of the original without a literal rendering that would confuse English readers about the actual referent.</p>",
    "12": "<p><em>miktāb</em> (H4385) — a letter, written document; the term appears only here and Jer 36:6 in the Hebrew Bible for a prophetic communication in written form. This is the only letter Elijah is said to have written. The chronological puzzle: Elijah was taken up to heaven before Jehoram&rsquo;s Judean reign (cf. 2 Kgs 2). Rabbinic tradition resolved this by positing Elijah wrote the letter before his translation and it was delivered later, or that the reference is to an earlier letter to Ahab&rsquo;s dynasty more broadly. The Chronicler uses the letter as a direct prophetic address to Jehoram regardless of this historical puzzle.</p>",
    "13": "<p><em>ûbᵉnê ʾāḇîḵā hatôḇîm mimmeḵā haragtā</em> (&lsquo;you have murdered your brothers, your own family, who were better men than you&rsquo;) — the phrase <em>hatôḇîm mimmeḵā</em> (&lsquo;better than you&rsquo;) is a rare explicit comparative moral judgment within a prophetic oracle. The comparison inverts the usual evaluation: the king who survived is morally inferior to those he killed. <em>wayyazᵉneh ʾet-Yᵉhûdāh wᵉʾet-yōšᵉḇê Yᵉrûšālayim</em> — the verb repeated from v11, forming a bracket around the prophetic indictment.</p>",
    "14": "<p><em>maggēpāh gᵉdôlāh</em> (&lsquo;devastating blow&rsquo;) — <em>maggēpāh</em> (H4046): a blow, plague, striking; often used for divine punishment through epidemic or military defeat. The sequence of objects struck — <em>ʿamᵉḵā ûḇānêḵā ûnāšêḵā wᵉḵol-rᵉkûšeḵā</em> (people, children, wives, all possessions) — follows the ascending order of personal loss, with the attack on family as the most devastating consequence. This fulfillment is narrated in v16-17.</p>",
    "15": "<p><em>ḥŏlî məʿêḵā</em> (&lsquo;bowel disease&rsquo;) — <em>maʿeh</em> (H4578): the entrails, bowels; the disease produces progressive intestinal deterioration. The phrase <em>ʿad-ṣēʾt māʿêḵā min-haḥŏlî yāmîm ʿal-yāmîm</em> (&lsquo;until your intestines come out because of the illness, day by day&rsquo;) is graphically clinical for prophetic literature, emphasizing the gradual, publicly visible nature of divine judgment. The fulfillment at v18-19 confirms the letter&rsquo;s authority.</p>",
    "16": "<p><em>ûbaʿĔlîšāʾ ʿōrēr YHWH ʿal-Yᵉhôrām</em> (&lsquo;the LORD stirred up against Jehoram&rsquo;) — <em>ʿûr</em> (H5782, Hiphil): to arouse, wake up, stir; YHWH as the agent who mobilizes foreign armies against his disobedient people (cf. Isa 10:5; Jer 51:11). <em>haPᵉlištîm wᵉhāʿărāḇîm</em> (Philistines and Arabians) — the Arabians (<em>ʿărāḇîm</em>, H6163) here are the nomadic peoples bordering the Negev/Sinai region. <em>ʿal-yad haKûšîm</em> (&lsquo;who bordered the Cushites&rsquo;) — adjacent to the Cushite regions, possibly meaning Arab tribes in the Ethiopian-border area.</p>",
    "17": "<p><em>wayyišbû ʾet-kol-hāreḵûš</em> (&lsquo;carried off everything&rsquo;) — <em>šāḇāh</em> (H7617): to take captive, lead away; <em>reḵûš</em> (H7399): movable property, possessions, wealth. The royal family is taken: <em>gam-bānāyw gam-nāšāyw</em> (sons and wives). The exception: <em>Yᵉhôʾāḥāz bᵉnô haqqāṭōn</em> (&lsquo;Jehoahaz his youngest son was left&rsquo;). In 2 Kgs 8:24 the same person is called Ahaziah; Jehoahaz is an alternative form of the same name (both contain YHWH + ʾāḥaz/ʾāhaz, seize). The Chronicler uses the longer form here only.</p>",
    "18": "<p><em>wayyiggoph YHWH ʾet-Yᵉhôrām ḥŏlî lōʾ lᵉrāpāʾ</em> (&lsquo;the LORD afflicted Jehoram with an incurable disease&rsquo;) — <em>nāgap</em> (H5062): to smite, strike; used for divine blows in plague contexts. <em>lōʾ lᵉrāpāʾ</em> (&lsquo;with no healing&rsquo;) — <em>rāpāʾ</em> (H7495): to heal; the combination &lsquo;without healing&rsquo; appears also in Jer 14:19 and Mic 1:9 for irremediable divine judgment. The fulfillment of Elijah&rsquo;s letter (v15) is exact: the disease is identical to what was promised.</p>",
    "19": "<p><em>bᵉtaḥălûʾîm rāʿîm</em> (&lsquo;in severe pain&rsquo;) — <em>taḥălûʾ</em> (H8463): sickness, disease; the plural intensive suggests overwhelming suffering. <em>wᵉlōʾ ʿāśû-lô ʿammô śᵉrēpāh kišrēpat ʾăḇōtāyw</em> (&lsquo;his people did not honor him with a burning of spices as they had done for his ancestors&rsquo;) — the royal funeral included a ceremonial burning of spices as honor (cf. 16:14 for Asa&rsquo;s honorable burial). The absence marks royal disgrace: Jehoram died unwept and unhonored, with no public mourning.</p>",
    "20": "<p><em>ûlōʾ-ḥemdāh hālaḵ</em> (&lsquo;he passed away, to no one&rsquo;s regret&rsquo;) — <em>ḥemdāh</em> (H2532): desirableness, pleasure, delight; the negative prefix creates the idiom &lsquo;without anyone desiring him&rsquo; — no one longed for or grieved at his death. The burial formula <em>wayyiqbᵉrûhû bᵉʿîr Dāwîd</em> is followed immediately by the disqualifying clause <em>wᵉlōʾ bᵉqiḇrôt hamᵉlāḵîm</em> (&lsquo;but not in the royal tombs&rsquo;) — exclusion from the dynastic burial ground is the ultimate posthumous dishonor, recalling the exclusion of the wicked from communal burial rights.</p>"
  },
  "22": {
    "1": "<p><em>haggᵉdûd</em> (H1416) — the raiding party, band; the Arabic <em>ʿărāḇîm</em> as nomadic raiders who killed all the older sons in the camp. The phrase <em>haggᵉdûd habbāʾ ḇammaḥăneh</em> is the raiding contingent in the army camp. The Chronicler explains why Ahaziah — the youngest — becomes king: not dynastic choice but survival necessity. The parallel in 2 Kgs 9:27-29 gives the death in a slightly different sequence.</p>",
    "2": "<p><em>ben-ʾarbaʿîm ûšetayim šānāh ʾAḥazyāhû</em> (&lsquo;Ahaziah was forty-two years old&rsquo;) — a well-known textual difficulty: 2 Kgs 8:26 reads <em>ben-ʿeśrîm ûštayim</em> (&lsquo;twenty-two years old&rsquo;). Since his father Jehoram died at forty (21:5, 20), an age of forty-two for Ahaziah is impossible. The MT of Chronicles has an error (<em>ʾarbaʿîm</em> for <em>ʿeśrîm</em>) probably introduced by scribal confusion between the Hebrew numerals. The LXX Codex Alexandrinus reads twenty-two. The MKT follows the MT but readers should note the reading in 2 Kgs 8:26. <em>bat-ʿOmrî</em> (&lsquo;daughter of Omri&rsquo;) — Athaliah is the daughter of Ahab (so explicitly in v2 of the same verse), but Omri is named as the dynasty-founder; the identification by dynastic grandfather is a formal title.</p>",
    "3": "<p><em>gam-hûʾ hālaḵ bᵉdarᵉḵê bêt ʾAḥʾāḇ</em> (&lsquo;he too walked in the ways of the house of Ahab&rsquo;) — the adverb <em>gam</em> (&lsquo;also, too&rsquo;) links Ahaziah to his father Jehoram (21:6). <em>yôʿaṣtô lᵉrāšaʿ</em> — from <em>yaʿaṣ</em> (H3289, advise) and <em>rāšaʿ</em> (H7561, act wickedly): she counseled him to wickedness. The mother as evil advisor is a rare explicit characterization; the Chronicler attributes Ahaziah&rsquo;s failure to deliberate domestic influence rather than autonomous decision.</p>",
    "4": "<p><em>wayyaʿaś hāraʿ bᵉʿênê YHWH kᵉbêt ʾAḥʾāḇ</em> — the standard condemnation formula applied to the Ahab dynasty. <em>hēm-hāyû lô yôʿᵃṣîm ʾaḥᵃrê môt ʾāḇîw lᵉmašḥît lô</em> (&lsquo;after his father&rsquo;s death they became his advisers and led him to his ruin&rsquo;) — <em>mašḥît</em> (H4889): destruction, ruin; the Hiphil participle of <em>šāḥat</em> (to destroy). The Ahab court functionaries outlived Jehoram and continued their influence into Ahaziah&rsquo;s reign.</p>",
    "5": "<p><em>bᵉʿaṣātām hālaḵ</em> (&lsquo;following their advice&rsquo;) — <em>ʿēṣāh</em> (H6098): advice, counsel; the connection back to v3-4 closes the counsel theme. The battle at Ramoth-gilead with Hazael of Syria (<em>Ḥăzāʾēl melek ʾĂrām</em>) recycles the battle where Ahab died (1 Kgs 22); now his son Joram is wounded there. <em>wayyakkû hāʾărammîm ʾet-Yôrām</em> (&lsquo;the Syrians wounded Joram&rsquo;) — <em>nākāh</em> (H5221): to smite, wound.</p>",
    "6": "<p><em>Rāmāh</em> — a shortened form of Ramoth-gilead; the wounded Joram recovers in Jezreel. The Chronicler uses both the full and short forms in proximity (Ramoth-gilead in v5, Ramah here), maintaining fidelity to his sources. Ahaziah&rsquo;s visit to the sick Joram — <em>liryʾōt ʾet-Yôrām ben-ʾAḥʾāḇ bᵉYizrᵉʿēl kî-ḥôleh hûʾ</em> — becomes the occasion for his death (vv7-9).</p>",
    "7": "<p><em>ûmēʾĕlōhîm hāyᵉtāh tᵉbûʾat ʾAḥazyāhû lābôʾ ʾel-Yôrām</em> (&lsquo;Ahaziah&rsquo;s downfall came about through God&rsquo;s design&rsquo;) — <em>mēʾĕlōhîm</em>: literally &lsquo;from God&rsquo;; the prepositional phrase marks divine causation behind the political sequence. <em>tᵉbûʾāh</em> (H8395) is an unusual word for ruin/downfall — used only here and Ps 89:41 in this sense. The Chronicler attributes Ahaziah&rsquo;s death at Jehu&rsquo;s hand to YHWH&rsquo;s providential design: Jehu was <em>mĕšûaḥ YHWH lᵉhakrît ʾet-bêt ʾAḥʾāḇ</em> (&lsquo;anointed by the LORD to destroy the house of Ahab&rsquo;).</p>",
    "8": "<p><em>ûḇᵉhiššāpᵉṭ Yēhûʾ ʿim-bêt ʾAḥʾāḇ</em> (&lsquo;while Jehu was carrying out judgment on the house of Ahab&rsquo;) — <em>šāpaṭ</em> (H8199): to judge, execute judgment; the Niphal <em>hiššāpᵉṭ</em> = to contend, execute, go to judgment with. <em>śārê Yᵉhûdāh ûḇᵉnê ʾaḥê ʾAḥazyāhû mᵉšārᵉtîm lᵉʾAḥazyāhû</em> (&lsquo;the princes of Judah and the sons of Ahaziah&rsquo;s brothers who were in attendance on him&rsquo;) — <em>šārat</em> (H8334): to minister, serve; these attendants were killed with Ahaziah&rsquo;s delegation.</p>",
    "9": "<p><em>wayyᵉḇaqqēš ʾet-ʾAḥazyāhû</em> (&lsquo;Jehu searched for Ahaziah&rsquo;) — <em>bāqaš</em> (H1245): to seek, search for; found hiding in Samaria (<em>mistattēr bᵉŠōmᵉrôn</em>). The burial eulogy preserved: <em>kî-ʾāmar ben-Yᵉhôšāpāṭ hûʾ ʾăšer-dāraš ʾet-YHWH bᵉḵāl-lᵉḇāḇô</em> (&lsquo;for they said, he is the grandson of Jehoshaphat, who sought the LORD with all his heart&rsquo;) — <em>dāraš</em> (H1875): to seek, inquire; the Chronicler&rsquo;s key verb for genuine religious devotion. The grandfather&rsquo;s commendation survives as the only positive note for Ahaziah&rsquo;s burial.</p>",
    "10": "<p><em>watāqom ʾAtalyāhû ʾēm ʾAḥazyāhû</em> (&lsquo;Athaliah the mother of Ahaziah rose up&rsquo;) — <em>qûm</em> in its decisive action sense. <em>watᵉʾabbēd ʾet kol-zeraʿ hammamlāḵāh</em> (&lsquo;she eliminated the entire royal family of Judah&rsquo;) — <em>ʾāḇad</em> (H6) in the Piel: to destroy, put to death. <em>zeraʿ hammamlāḵāh</em>: the seed/offspring of the kingdom, i.e., all Davidic heirs. This is the Chronicler&rsquo;s most dramatic moment of threat to the Davidic promise (cf. 21:7): only the <em>nîr</em> of 21:7 keeps the covenant alive through the hidden child Joash.</p>",
    "11": "<p><em>wayyiqqaḥ Yᵉhôšaḇʿat</em> (&lsquo;Jehoshabeath took&rsquo;) — her name <em>Yᵉhôšaḇʿat</em> means &lsquo;the LORD swears&rsquo; or &lsquo;the LORD is an oath-keeper&rsquo;. The Chronicler adds unique information: she was <em>ʾišet Yᵉhôyādāʿ hakkōhēn</em> (wife of Jehoiada the priest) and <em>ʾăḥôt ʾAḥazyāhû</em> (sister of Ahaziah), making her both royal princess and priest&rsquo;s wife — her dual status enables access to both the palace (to steal Joash) and the temple (to hide him). <em>gānaḇ</em> (H1589): to steal, take secretly.</p>",
    "12": "<p><em>wayhî ʾittām bᵉbêt hāʾĕlōhîm mitḥabbēʾ šēš šānîm</em> (&lsquo;he remained hidden with them in the house of God for six years&rsquo;) — <em>ḥāḇāʾ</em> (H2244, Hithpael): to hide oneself; the hidden Davidic heir in the temple is the Chronicler&rsquo;s most pregnant image of the tension between dynastic threat and divine preservation. Six years of concealment in YHWH&rsquo;s house while Athaliah rules — the contrast between the false ruler in the palace and the legitimate king hidden in the sanctuary is deliberate.</p>"
  },
  "23": {
    "1": "<p><em>wayyitḥazzaq Yᵉhôyādāʿ</em> (&lsquo;Jehoiada took courage&rsquo;) — the same verb <em>ḥāzaq</em> (H2388) used for Jehoram&rsquo;s self-assertion (21:4) is here used positively: Jehoiada strengthened himself for righteous action. He enters <em>ḇᵉrît</em> (covenant) with five military commanders; the naming of all five (<em>ʾAzaryāhû ben-Yᵉrôḥām</em>, etc.) signals authentic historical memory. The covenant with commanders is the institutional mechanism for the Joash restoration.</p>",
    "2": "<p><em>wayyāsûḇû bᵉYᵉhûdāh wayyiqbᵉṣû ʾet-halᵉwiyyim</em> (&lsquo;they traveled through Judah and assembled the Levites&rsquo;) — the Levites as the military force for the temple-centered coup is distinctively Chronicler; 2 Kgs 11 uses the Carites (foreign mercenaries) instead. The Chronicler substitutes Levites throughout, consistent with his theological interest in proper cult personnel. <em>rāʾšê hāʾāḇôt</em> (&lsquo;heads of the ancestral families&rsquo;) — <em>bêt-hāʾāḇôt</em> (H1): the kinship-group unit of clan organization in Chronicles.</p>",
    "3": "<p><em>wayyikrōt kol-haqqāhāl bᵉrît bᵉbêt hāʾĕlōhîm</em> (&lsquo;all the assembly made a covenant in the house of God&rsquo;) — the covenant takes place in the sanctuary, sanctifying the political act with divine witness. Jehoiada&rsquo;s declaration: <em>hinnēh ben-hammelek yimlōḵ kaʾăšer dibber YHWH ʿal-bᵉnê Dāwîd</em> (&lsquo;the king&rsquo;s son shall reign, as the LORD promised concerning the sons of David&rsquo;) — the Davidic promise is the legal-theological ground for Joash&rsquo;s right to the throne despite Athaliah&rsquo;s occupation of it.</p>",
    "4": "<p><em>šōʿărîm bassippôt</em> (&lsquo;gatekeepers at the temple entrances&rsquo;) — <em>šōʿēr</em> (H7778): doorkeeper, gatekeeper; a distinct Levitical function (cf. 1 Chr 9:17-27). The three-way division of the guard force distributes oversight across the key access points: temple gates, palace, and the Foundation Gate. The Sabbath rotation is exploited to double the guard strength without breaking normal patterns of movement.</p>",
    "5": "<p><em>šaʿar hayyᵉsôd</em> (&lsquo;Foundation Gate&rsquo;) — the <em>yᵉsôd</em> (H3247): foundation, base; a gate name found only here. 2 Kgs 11:6 reads &lsquo;the gate of Sur&rsquo; instead — either different names for the same gate or different sources. The third station, <em>ḥaṣrôt bêt-YHWH</em> (&lsquo;courts of the LORD&rsquo;s house&rsquo;), is where the general populace stands as witnesses to the coronation.</p>",
    "6": "<p><em>wᵉhēm yibbōʾû kî-qᵉdōšîm hēm</em> (&lsquo;for they are holy&rsquo;) — the holiness of priests and Levites as grounds for exclusive sanctuary access is the foundational principle of Israelite sacred space. The common people (<em>ʿam</em>) keep the LORD&rsquo;s watch but may not enter the inner areas. This principle (upheld even during a political coup) reflects the Chronicler&rsquo;s consistent concern that cultic propriety not be violated even when urgent political action is required.</p>",
    "7": "<p><em>ʾîš wᵉkēlāyw bᵉyādô</em> (&lsquo;each man with his weapons in hand&rsquo;) — the armed Levites as temple guard; the Chronicler&rsquo;s substitution of Levites for the Carites (2 Kgs 11:4) makes the protective force ecclesiastically proper. <em>wᵉkol-habbāʾ ʾel-habbayit yûmāt</em> (&lsquo;anyone who tries to enter the house is to be put to death&rsquo;) — the temple&rsquo;s inviolability combined with the security cordon around the king.</p>",
    "8": "<p><em>kî lōʾ-šillēaḥ Yᵉhôyādāʿ hakkōhēn ʾet-hammaḥlᵉqôt</em> (&lsquo;for Jehoiada did not release the divisions&rsquo;) — <em>maḥlāqôt</em> (H4256): divisions, courses; the Levitical rotational system normally alternated weekly; Jehoiada kept both incoming and outgoing divisions active simultaneously, doubling the force without arousing suspicion about unusual mobilization.</p>",
    "9": "<p><em>hāʾźānôt wᵉhāšᵉlāṭîm wᵉhammāginnîm ʾăšer lammeleḵ Dāwîd</em> (&lsquo;the spears, bucklers, and shields that had belonged to King David&rsquo;) — the weapons stored as temple votive offerings since David&rsquo;s reign (cf. 1 Sam 21:9; 1 Chr 26:26-27). The issuing of David&rsquo;s own weapons for Joash&rsquo;s restoration ceremony adds symbolic weight: the Davidic king is restored using David&rsquo;s own arsenal.</p>",
    "10": "<p><em>miyyāmîn habbayit wᵉʿad-śᵉmōʾl habbayit lammizᵉbēaḥ ûlabbayit</em> (&lsquo;from the south side to the north side of the temple, along the altar and the house&rsquo;) — the positioning of the armed guard forms a protective ring around the entire temple structure, with the king at center. The spatial description reflects careful military planning: no gap in the perimeter that would allow Athaliah&rsquo;s supporters to intervene.</p>",
    "11": "<p><em>wayyittᵉnû ʿālāyw ʾet-hāʿēḏût</em> (&lsquo;gave him the testimony&rsquo;) — <em>hāʿēḏût</em> (H5715): the testimony, the covenant document; probably the Torah scroll (cf. Deut 17:18-20, where the king is to write a copy of the law and read it). The coronation of the Israelite king involved receiving the covenant document as symbol of his obligation to rule under YHWH&rsquo;s law. The MKT renders &lsquo;testimony&rsquo; as a Hebraism rather than &lsquo;a copy of the covenant.&rsquo; <em>wayyimšᵉḥûhû</em> (&lsquo;anointed him&rsquo;) — Jehoiada and his sons perform the royal unction; the priestly role in coronation is emphasized by the Chronicler.</p>",
    "12": "<p><em>wayyišmaʿ ʿAtalyāhû ʾet-qôl hāʿām hārāṣîm wᵉhammᵉhallᵉlîm ʾet-hammelek</em> (&lsquo;Athaliah heard the noise of the people running and praising the king&rsquo;) — the <em>qôl</em> (voice/noise) of praise is the alarm signal that betrays the coup to Athaliah. <em>hārāṣîm</em> (H7323): those running, the running crowd; <em>mᵉhallᵉlîm</em> (Piel participle of <em>hālal</em>, H1984): praising, singing praises — the worship shout that accompanies the coronation.</p>",
    "13": "<p><em>hinnēh hammelek ʿōmēd ʿal-hāʿammûd</em> (&lsquo;the king standing by his pillar&rsquo;) — <em>hāʿammûd</em> (H5982): the pillar; the king&rsquo;s designated standing position at the temple entrance (cf. 2 Kgs 23:3 for the same position used by Josiah). <em>hašśārîm wᵉhaḥăṣōṣrôt ʿal-hammelek</em> — the officers and trumpeters flanking the king ceremonially. <em>ûmᵉšōrᵉrîm wᵉhammaddiᵉʿîm</em> (&lsquo;singers and musicians leading praise&rsquo;) — the full royal court ceremonial accompanies the coronation. <em>wattiqqraʿ ʾAtalyāhû ʾet-bigdêhā</em> — tearing garments as expression of horror: <em>qešer qešer</em> (&lsquo;treason, treason!&rsquo;) — <em>qeśer</em> (H7195): conspiracy, treason.</p>",
    "14": "<p><em>wayyōṣēʾ Yᵉhôyādāʿ hakkōhēn ʾet-śārê hameʾôt pᵉqûdê hahayil</em> (&lsquo;Jehoiada the priest brought out the captains who commanded the troops&rsquo;) — <em>pāqad</em> (H6485): to appoint, command over. The command <em>hôṣîʾû ʾōtāh miḇʿaḏ laśśᵉdērôt</em> (&lsquo;take her outside the ranks&rsquo;) — <em>śᵉdērôt</em> (H7713): rows, ranks; through/behind the guard ranks, away from the sanctuary area. The prohibition: <em>wᵉhammāmît ʾaḥᵃrêhā haregû-ḥāreḇ</em> (&lsquo;put to death anyone who follows her&rsquo;) while keeping the execution outside the temple: <em>kî ʾāmar hakkōhēn ʾal-tᵉmîtûhā bêt-YHWH</em> (&lsquo;do not kill her in the LORD&rsquo;s house&rsquo;).</p>",
    "15": "<p><em>šaʿar sûs hammᵉbôʾ bêt-hammelek</em> (&lsquo;the Horse Gate at the entrance to the palace&rsquo;) — the Horse Gate was a palace entrance in Jerusalem (cf. Neh 3:28; Jer 31:40); a secular, administrative location chosen deliberately for Athaliah&rsquo;s execution to keep blood-guilt away from the sanctuary precincts. The execution verb <em>wayyᵉmîtûhā šām</em> (&lsquo;they killed her there&rsquo;) is unelaborated — the Chronicler is more interested in the principle (execution outside the temple) than the physical act.</p>",
    "16": "<p><em>wayyikrōt Yᵉhôyādāʿ bᵉrît bênô ûḇên kol-hāʿām ûḇên hammelek lihyôt lᵉʿam YHWH</em> (&lsquo;Jehoiada made a covenant between himself, all the people, and the king, that they would be the LORD&rsquo;s people&rsquo;) — a three-party covenant: priest, people, and king, all bound to YHWH. The covenant formula <em>lihyôt lᵉʿam YHWH</em> (&lsquo;to be the LORD&rsquo;s people&rsquo;) is the covenantal commitment language of Sinai (Exod 6:7; Jer 30:22); Jehoiada&rsquo;s covenant re-enacts the national covenant commitment as the basis for the restored monarchy.</p>",
    "17": "<p><em>wayyāḇōʾû kol-hāʿām bêt-habbāʿal wayyitṣûhû</em> (&lsquo;all the people went to the house of Baal and tore it down&rsquo;) — <em>nāṯaṣ</em> (H5422): to tear down, break down; iconoclasm as the immediate expression of covenant renewal. <em>ûmattān kōhēn habbāʿal hāragû lipnê hammizbᵉḥôt</em> (&lsquo;and killed Mattan the priest of Baal in front of the altars&rsquo;) — the execution of the Baal priest at the altar of the destroyed shrine echoes Elijah&rsquo;s killing of the Baal prophets at Carmel (1 Kgs 18:40). The proper worship center (the temple) is restored by destroying the false one.</p>",
    "18": "<p><em>wayyāśem Yᵉhôyādāʿ pᵉqûddôt bêt-YHWH bᵉyad hakᵉhănîm halwîyyim</em> (&lsquo;Jehoiada reestablished the temple administration under the priests and Levites&rsquo;) — <em>pᵉquddāh</em> (H6486): oversight, appointed service. The phrase <em>ʾăšer ḥālaq Dāwîd ʿal-bêt YHWH</em> (&lsquo;the divisions David had appointed&rsquo;) links the restored worship explicitly to the Davidic liturgical order, the Chronicler&rsquo;s perpetual touchstone for correct worship. <em>bᵉśimḥāh ûḇᵉšîr ʿal-yᵉdê Dāwîd</em> (&lsquo;with the rejoicing and singing that David had ordained&rsquo;) — Davidic music as liturgical standard.</p>",
    "19": "<p><em>wayyaʿᵃmēd šōʿᵃrîm ʿal-šaʿᵃrê bêt-YHWH</em> (&lsquo;he stationed gatekeepers at the entrances to the LORD&rsquo;s house&rsquo;) — the restoration of proper gate-keeping reinstates the holiness barrier after Athaliah&rsquo;s defilement. <em>ûlᵉkol-ṭāmēʾ lᵉḵol-dāḇār</em> (&lsquo;so that nothing unclean in any way could enter&rsquo;) — <em>ṭāmēʾ</em> (H2931): ritually unclean; the holiness of the sanctuary requires that exclusion of impurity be systematically enforced, not assumed.</p>",
    "20": "<p><em>wayyōrîdû ʾet-hammelek mibêt YHWH</em> (&lsquo;brought the king down from the LORD&rsquo;s house&rsquo;) — the procession moves from sanctuary (where coronation occurred) to throne room; the direction &lsquo;down&rsquo; reflects Jerusalem&rsquo;s topography (the temple mount is higher than the palace precincts). <em>wayyôšîḇû ʾet-hammelek ʿal-kissēʾ hammamlāḵāh</em> (&lsquo;seated the king on the royal throne&rsquo;) — the political enthronement follows the religious coronation; the two steps together constitute the full installation of the Davidic king.</p>",
    "21": "<p><em>wayyiśmaḥ kol-ʿam-hāʾāreṣ wᵉhāʿîr šāqᵉṭāh</em> (&lsquo;all the people of the land rejoiced, and the city was at peace&rsquo;) — <em>šāqaṭ</em> (H8252): to be at rest, undisturbed, tranquil; used for post-war quiet after successful political transition. <em>ʿam-hāʾāreṣ</em> (&lsquo;people of the land&rsquo;) is a sociological designation in Chronicles for the Judean citizenry as a political body with the power to validate or reject royal accessions. The closing formula <em>wᵉʾAtalyāhû hêmîtû beḥāreḇ</em> (&lsquo;Athaliah had been killed with the sword&rsquo;) is syntactically subordinated to the peace that follows her removal.</p>"
  },
  "24": {
    "1": "<p><em>ben-šeḇaʿ šānîm Yôʾāš bᵉmalᵉkô</em> (&lsquo;Joash was seven years old when he became king&rsquo;) — the youngest accession age recorded in the Hebrew Bible. His forty-year reign (<em>ʾarbaʿîm šānāh mālaḵ bîrûšālāim</em>) is one of the longest in Judah&rsquo;s history. The mother&rsquo;s name, <em>Ziḇyāh miBᵉʾēr-šāḇaʿ</em>, signals southern Negev origin; the name <em>Ziḇyāh</em> means &lsquo;gazelle.&rsquo;</p>",
    "2": "<p><em>wayyaʿaś Yôʾāš hayyāšār bᵉʿênê YHWH kol-yᵉmê Yᵉhôyādāʿ hakkōhēn</em> (&lsquo;Joash did what was right in the sight of the LORD all the days of Jehoiada the priest&rsquo;) — the qualification <em>kol-yᵉmê Yᵉhôyādāʿ</em> is the structural key to the chapter&rsquo;s entire narrative arc: faithfulness conditioned on priestly mentorship, which fails when that mentorship ends (v17-18). The Chronicler flags Joash&rsquo;s dependence from the outset, making the later apostasy narratively inevitable once the mentor dies.</p>",
    "3": "<p><em>wayyiśśāʾ-lô Yᵉhôyādāʿ nāšîm šetayim</em> (&lsquo;Jehoiada chose two wives for him&rsquo;) — the priest overseeing the king&rsquo;s marriage arrangements reflects Jehoiada&rsquo;s extraordinary guardianship role. Two wives (not the polygamous excess associated with Solomon&rsquo;s downfall) is recorded without condemnation; the Chronicler notes sons and daughters as a sign of dynastic blessing. The verse functions as a quiet positive marker before the temple repair narrative.</p>",
    "4": "<p><em>wayhî ʾaḥᵃrê kēn hāyāh ʿim-lēḇ Yôʾāš lᵉḥaddēš ʾet-bêt YHWH</em> (&lsquo;Joash decided to repair the LORD&rsquo;s house&rsquo;) — <em>ḥādaš</em> (H2318, Piel): to renew, restore, repair; the same verb for covenant renewal. <em>hāyāh ʿim-lēḇ</em> (&lsquo;it was in his heart&rsquo;) — the idiom of purposed intention; Joash&rsquo;s initiative is genuinely his own (not prompted here by Jehoiada). The temple repair is the first major narrative sequence.</p>",
    "5": "<p><em>liqqᵉṭ-kesep mikkol-Yiśrāʾēl lᵉḥazzēq ʾet-bêt-ʾĕlōhêḵem mišānāh bᵉšānāh</em> (&lsquo;collect money from all Israel year by year to repair the house of your God&rsquo;) — the annual collection reflects the Mosaic sanctuary tax (Exod 30:12-16). <em>wᵉʾattem tᵉmahᵃrû laddāḇār wᵉlōʾ mîharrû halᵉwiyyim</em> (&lsquo;Do this promptly. But the Levites did not act promptly&rsquo;) — <em>māhar</em> (H4116): to hurry, hasten; the same verb used positively and negatively in rapid sequence, highlighting the gap between royal command and Levitical execution.</p>",
    "6": "<p><em>maśśaʾt Mōšeh ʾeḇed-YHWH wᵉqahal Yiśrāʾēl</em> (&lsquo;the collection ordered by Moses the servant of God and the assembly of Israel&rsquo;) — the dual authority cited for the tax: Mosaic law and assembly ratification. <em>miškan hāʿēḏût</em> (&lsquo;the tent of testimony&rsquo;) — the Exodus-era designation for the tabernacle; the Chronicler preserves the archaic name, connecting the contemporary collection to its Sinai origins. The king&rsquo;s rebuke of Jehoiada is notable: even the chief priest is accountable to royal initiative in civil-religious matters.</p>",
    "7": "<p><em>kî ʿAtalyāhû hammiršaʿat bānêhā pāṣᵉṣû ʾet-bêt hāʾĕlōhîm</em> (&lsquo;the sons of that wicked woman Athaliah had broken into the house of God&rsquo;) — <em>pāṣaṣ</em> (H6555): to break open, break through; the rare verb for violent forced entry. <em>hammiršaʿat</em> (&lsquo;that wicked woman&rsquo;) — the feminine form of <em>rāšāʿ</em> (wicked) used as an epithet; the Chronicler&rsquo;s only direct personal pejorative for a named individual. The desecration by Athaliah&rsquo;s sons — using dedicated things (<em>qᵉdāšôt</em>) for Baal — is the historical context for the urgent need for temple repair.</p>",
    "8": "<p><em>wayyōʾmēr hammelek wayyaʿᵃśû ʾarôn ʾeḥāḏ</em> (&lsquo;at the king&rsquo;s command they made a chest&rsquo;) — <em>ʾārôn</em> (H727): chest, box; the same word for the ark of the covenant, but here a collection chest. The placement <em>miḥûṣ lᵉšaʿar bêt-YHWH</em> (&lsquo;outside the gate of the LORD&rsquo;s house&rsquo;) makes the collection maximally accessible to all who pass through. The public placement of the chest inverts the secrecy of the previous repair attempts.</p>",
    "9": "<p><em>wayyittᵉnû-qôl bîhûdāh ûḇîrûšālāim</em> (&lsquo;they issued a proclamation throughout Judah and Jerusalem&rsquo;) — <em>nātan qôl</em> (gave/raised a voice): a technical idiom for official public announcement. The proclamation references <em>maśśaʾt Mōšeh ʾeḇed-hāʾĕlōhîm ʿal-Yiśrāʾēl bammidḇār</em> (&lsquo;the contribution Moses the servant of God required of Israel in the wilderness&rsquo;) — locating the current tax in the Sinai narrative gives it maximum covenantal legitimacy.</p>",
    "10": "<p><em>wayyiśmaḥû kol-haśśārîm wᵉḵol-hāʿām wayyāḇîʾû wayyašlîḵû lāʾārôn</em> (&lsquo;all the princes and all the people rejoiced and brought their contributions, casting them into the chest&rsquo;) — <em>šālak</em> (H7993, Hiphil): to throw, cast; <em>ʿad-lᵉkallôt</em> (&lsquo;until it was full&rsquo;) — the enthusiastic response fills the chest repeatedly. The willing giving in contrast to the Levites&rsquo; dilatoriness (v5) demonstrates that popular enthusiasm exceeded institutional initiative.</p>",
    "11": "<p><em>bᵉʿēt yāḇîʾû ʾet-hāʾārôn ʾel-pᵉquddāt hammelek bᵉyad halᵉwiyyim</em> (&lsquo;whenever the Levites brought the chest to the king&rsquo;s officers&rsquo;) — the oversight mechanism: royal secretary (<em>sōpēr hammelek</em>) and high priest&rsquo;s officer jointly empty the chest and return it, creating a dual audit. <em>wayyaʿᵃśû-ḵen yôm bᵉyôm</em> (&lsquo;they did this day after day&rsquo;) — repeated daily collection and oversight; the administrative regularity is an earnest of good governance.</p>",
    "12": "<p><em>wayyittᵉnûhû hammelek wîhôyādāʿ ʾel-ʿōśê mᵉlāʾḵat ʿăḇōdat bêt-YHWH</em> (&lsquo;the king and Jehoiada gave the money to those who supervised the work on the LORD&rsquo;s house&rsquo;) — the project management is at the royal-priestly level, with skilled labor hired: <em>ḥāṣᵉḇê ʾāḇānîm ûḇōnîm</em> (stone-cutters and builders), <em>ḥārāšê barzel ûnᵉḥōšet</em> (ironworkers and bronzesmiths) — the same craftsmen categories as the original temple construction (cf. 2 Chr 2:7, 14).</p>",
    "13": "<p><em>wayᵉqîmû ʾet-habbayit ʾĕlōhîm ʿal-mattᵉkōnᵉtô</em> (&lsquo;they restored the house of God to its proper condition&rsquo;) — <em>mattᵉkōnet</em> (H8506): established condition, proper state; the temple is returned to its foundational standard. <em>wayyᵉḥazzᵉqûhû</em> (&lsquo;and reinforced it&rsquo;) — <em>ḥāzaq</em> (H2388, Piel): to strengthen, reinforce; the Piel intensive suggesting thoroughgoing structural renewal, not minimal patching.</p>",
    "14": "<p><em>kᵉlê šērēt wᵉhaʿᵃlôt kappôt ûkᵉlê zāhāḇ wāḵesef</em> (&lsquo;vessels for service and offerings, spoons and vessels of gold and silver&rsquo;) — the liturgical equipment restored includes both functional vessels and precious decorative objects. The ongoing offering: <em>wayyaʿᵃlû ʿōlôt bᵉḇêt-YHWH tāmîd kol-yᵉmê Yᵉhôyādāʿ</em> (&lsquo;they offered burnt offerings in the LORD&rsquo;s house continually all the days of Jehoiada&rsquo;) — the <em>tāmîd</em> (perpetual offering) resumes as the sign of restored worship. The phrase <em>kol-yᵉmê Yᵉhôyādāʿ</em> again marks the temporal qualifier that v2 established as the hinge of Joash&rsquo;s faithfulness.</p>",
    "15": "<p><em>wayyizqan Yᵉhôyādāʿ wayyiśbaʿ yāmîm wayyāmot ben-mʾāh ûšᵉlōšîm šānāh bᵉmôtô</em> (&lsquo;Jehoiada grew old and full of years, and he died at the age of one hundred and thirty&rsquo;) — <em>śāḇaʿ yāmîm</em> (&lsquo;full of years/days&rsquo;) is the honorific formula used for Abraham (Gen 25:8) and Job (Job 42:17). Jehoiada at 130 exceeds Moses (120, Deut 34:7) and Joshua (110, Josh 24:29) — the only non-patriarchal figure given a longer lifespan in the OT. The longevity implicitly commends his faithfulness: long life as covenant blessing.</p>",
    "16": "<p><em>wayyiqbᵉrûhû bᵉʿîr Dāwîd ʿim-hamᵉlāḵîm</em> (&lsquo;they buried him in the city of David among the kings&rsquo;) — Jehoiada is buried with the Davidic kings, an honor reserved for no other priest in the Hebrew Bible. The reason: <em>kî-ʿāśāh ṭôḇāh bᵉYiśrāʾēl ûḇiʾĕlōhîm ûḇᵉḇêtô</em> (&lsquo;because he had served Israel well — both toward God and toward his house&rsquo;). The tripartite summary of Jehoiada&rsquo;s service — to Israel, to God, and to the temple — is the Chronicler&rsquo;s fullest commendation of any non-royal figure.</p>",
    "17": "<p><em>wᵉʾaḥᵃrê môt Yᵉhôyādāʿ bāʾû śārê Yᵉhûdāh wayyišdᵃḥᵃwû lammelek</em> (&lsquo;after Jehoiada&rsquo;s death, the officials of Judah came and bowed before the king&rsquo;) — the political shift is immediate: new advisors replace the priest. <em>wayyikḇᵃdûhû</em> (&lsquo;and honored him&rsquo;) — <em>kāḇad</em> (H3513, Piel): to honor, make heavy/important; the officials flatter the king into receptivity for their idolatrous proposals. The structural parallel to Rehoboam&rsquo;s rejection of older counsel (2 Chr 10) is deliberate: young kings who defer to a new advisory class abandon the wisdom of their fathers.</p>",
    "18": "<p><em>wayyaʿaḇᵉdû ʾet-hāʾăšērîm wᵉʾet-hāʿᵃṣabbîm</em> (&lsquo;served the Asherah poles and idols&rsquo;) — <em>ʾăšērāh</em> (H842): the sacred tree or pole associated with the Canaanite goddess; <em>ʿᵃṣabbîm</em> (H6091): images, idols. <em>wayhî qeṣep ʿal-Yᵉhûdāh ûḇirûšālāim bᵉʾašmātām zōʾt</em> (&lsquo;wrath came upon Judah and Jerusalem because of this guilt&rsquo;) — <em>qeṣep</em> (H7110): wrath, indignation; <em>ʾašmāh</em> (H819): guilt, guilt-offering; the guilt of idolatry is the theological cause of the subsequent military defeat (vv23-24).</p>",
    "19": "<p><em>wayyišlaḥ bāhem nᵉḇiʾîm lᵉhāšîḇām ʾel-YHWH</em> (&lsquo;yet he sent prophets among them to bring them back to the LORD&rsquo;) — the pattern of prophetic warning before judgment is a structural constant in Chronicles: YHWH&rsquo;s judgment is never without prior appeal. <em>wayyāʿîdû bām wᵉlōʾ ʾāzānû</em> (&lsquo;they testified against them, but they would not listen&rsquo;) — <em>ʿûd</em> (H5749, Hiphil): to bear witness, testify against; <em>ʾāzan</em> (H238, Hiphil): to give ear, listen. The sequence: prophetic sending → warning → refusal establishes legal grounds for judgment.</p>",
    "20": "<p><em>wᵉrûaḥ ʾĕlōhîm lāḇᵉšāh ʾet-Zᵉḵaryāhû</em> (&lsquo;the Spirit of God clothed Zechariah&rsquo;) — <em>lāḇaš</em> (H3847): to clothe, put on; the Spirit-as-vestment idiom (cf. Judg 6:34 of Gideon; 1 Chr 12:18 of Amasai). The Spirit &lsquo;clothing&rsquo; a person expresses total possession and prophetic commission. Zechariah son of Jehoiada is mentioned only here; his message: <em>ʿăzaḇtem ʾet-YHWH wayyaʿaḇōḇ ʾetḵem</em> (&lsquo;you have forsaken the LORD and he has forsaken you&rsquo;) — <em>ʿāzaḇ</em> (H5800) repeated in chiastic structure: your abandonment produces divine abandonment.</p>",
    "21": "<p><em>wayyiqqᵉšᵉrû ʿālāyw wayyirgemûhû ʾeḇen bᵉmiṣwat hammelek</em> (&lsquo;they conspired against him and stoned him to death at the king&rsquo;s command&rsquo;) — <em>qāšar</em> (H7194, Hithpael): to bind together, conspire; <em>rāgam ʾeḇen</em> (&lsquo;to stone&rsquo;; H7275 + H68): stoning as mob execution. The location — <em>bᵉḥăṣar bêt-YHWH</em> (in the court of the LORD&rsquo;s house) — makes the murder a desecration of the very sanctuary Zechariah&rsquo;s father had restored and whose court Joash had filled with temple worship.</p>",
    "22": "<p><em>wᵉlōʾ-zāḵar Yôʾāš hammelek hahesed ʾăšer-ʿāśāh Yᵉhôyādāʿ ʾāḇîw ʿimmô</em> (&lsquo;Joash did not remember the kindness that Jehoiada his father had shown him&rsquo;) — <em>zāḵar ḥeseḏ</em> (&lsquo;remember kindness&rsquo;): the failure of <em>ḥeseḏ</em>-memory (loyal-love recall) is the moral pivot of the narrative. Joash forgets what Jehoiada did for him (hiding him, crowning him, advising him for forty years). Zechariah&rsquo;s dying words: <em>yidroš YHWH wᵉyirʾeh</em> (&lsquo;may the LORD see and avenge/require&rsquo;) — <em>dāraš</em> (H1875) in its judicial sense: to seek, hold accountable; the Chronicler&rsquo;s ironic use of the same root used for positive &lsquo;seeking God&rsquo; (cf. 22:9).</p>",
    "23": "<p><em>ûlitᵉqûpat haššānāh</em> (&lsquo;at the turn of the year&rsquo;) — <em>tᵉqûpāh</em> (H8622): circuit, turn; the year&rsquo;s end or the spring campaign season when armies traditionally marched (cf. 2 Sam 11:1). <em>wayyaʿal ḥêl ʾĂrām</em> (&lsquo;the Syrian army came against him&rsquo;) — the military punishment fulfilling the theological cause established in v18 (guilt/wrath). The scope of destruction: <em>wayyišlaḥû ʾet-kol-šᵉlālām ʾel-melek Dammeśeq</em> (&lsquo;sending all their plunder to the king of Damascus&rsquo;) — Judah&rsquo;s wealth stripped and transferred north.</p>",
    "24": "<p><em>kî bᵉmiṣʿar ʾănāšîm bāʾ ḥêl ʾĂrām ûḇᵉrōḇ ʾănāšîm nātan YHWH bᵉyādām ḥayil lārōḇ</em> (&lsquo;though the Syrian army came with only a small force, the LORD handed a very great army over to them&rsquo;) — the contrast of small force defeating large army is the Chronicler&rsquo;s characteristic reversal: human military calculus is inverted by divine determination. <em>kî ʿāzᵉḇû ʾet-YHWH ʾĕlōhê ʾăḇôtêhem</em> (&lsquo;because Judah had abandoned the LORD&rsquo;) — again <em>ʿāzaḇ</em> as the causal key; YHWH himself executes judgment: <em>ûḇᵉYôʾāš ʿāśû šᵉpāṭîm</em> (&lsquo;they executed judgment on Joash&rsquo;).</p>",
    "25": "<p><em>ûbᵉlektām mimmennû ʿāzᵉḇû ʾōtô bimᵉḥālûyîm rabbîm</em> (&lsquo;when the Syrians departed they left him severely wounded&rsquo;) — <em>maḥalûy</em> (H4245): sickness, wound; plural of intensity. <em>ʿal-dᵉmê ben-Yᵉhôyādāʿ hakkōhēn</em> (&lsquo;because of the blood of the son of Jehoiada the priest&rsquo;) — the explicit causal nexus: Zechariah&rsquo;s blood requires retribution (<em>dām</em> as legal claim); the servants are instruments of justice. <em>wayyiqbᵉrûhû bᵉʿîr Dāwîd wᵉlōʾ qᵉḇārūhû bᵉqiḇrôt hamᵉlāḵîm</em> (&lsquo;buried in the city of David, but not in the tombs of the kings&rsquo;) — the same posthumous dishonor as Jehoram (21:20), closing an inclusio of royal disgrace.</p>",
    "26": "<p><em>Zāḇāḏ ben-Šimᵉʾat hāʿamōnît wᵉYôzāḇāḏ ben-Šimrît haMôʾāḇît</em> — the Chronicler specifies both the assassins&rsquo; names and the foreign ethnic identity of their mothers (<em>hāʿamōnît</em>, Ammonite; <em>haMôʾāḇît</em>, Moabite). The parallel in 2 Kgs 12:21-22 records slightly different names (Jozachar and Jehozabad) and does not note the mothers&rsquo; ethnicity. The Chronicler&rsquo;s addition of foreign maternal lineage underscores the bitter irony: the king who abandoned YHWH&rsquo;s covenant was assassinated by the sons of foreign women — outsiders to the covenant community enacting judgment on a covenant-breaker.</p>",
    "27": "<p><em>ûḇānāyw wᵉrōḇ hammaśśāʾ ʿālāyw wᵉyissôd bêt hāʾĕlōhîm hinnām kᵉtûḇîm ʿal-midrash sēper hamᵉlāḵîm</em> (&lsquo;as for his sons, the many oracles about him, and the rebuilding of the house of God — these are recorded in the commentary on the book of the kings&rsquo;) — <em>midrāš</em> (H4097): the term appears only here and 13:22 in the Hebrew Bible; it derives from <em>dāraš</em> (to seek, inquire) and refers to an interpretive or expository commentary on an existing document. This is not the later rabbinic genre of Midrash but an early form of explanatory historiographical writing about royal history. The Chronicler cites it as a source document, suggesting a tradition of interpretive writing alongside the royal annals.</p>"
  }
}

def main():
    c = load_comm('mkt-original', '2chronicles')
    merge_comm(c, ORIGINAL)
    save_comm('mkt-original', '2chronicles', c)
    count = sum(len(v) for v in ORIGINAL.values())
    print(f'2chronicles mkt-original ch21-24: wrote {count} verses')

if __name__ == '__main__':
    main()
